import React, { useState, useRef, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Image, Form } from "react-bootstrap";

function Header({ timeLeft }) {
  const minutes = Math.floor(timeLeft / 60);
  const seconds = timeLeft % 60;

  const [username, setUsername] = useState("");

  useEffect(() => {
    if (localStorage.getItem("isLoggedIn") !== "true") {
      window.location.href = "/login";
    }

    const userData = localStorage.getItem("user");

    if (userData) {
      const user = JSON.parse(userData);
      console.log(user.username);
      setUsername(user.username); // or user.name if your API returns "name"
    }

    window.history.pushState(null, "", window.location.href);
    window.onpopstate = function () {
      window.history.pushState(null, "", window.location.href);
    };

    return () => {
      window.onpopstate = null;
    };
  }, []);

  const handleLogout = async () => {
    try {
      const userData = localStorage.getItem("user");

      let username = "";

      if (userData) {
        const user = JSON.parse(userData);
        username = user.username;
      }

      await fetch("http://localhost:8002/user/logout", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          username: username,
        }),
      });
    } catch (err) {
      console.log(err);
    }

    localStorage.clear();
    sessionStorage.clear();

    window.location.href = "/logout";
  };

  return (
    <div className="position-relative iq-banner">
      <nav class="navbar navbar-expand-lg bg-body-tertiary">
  <div class="container-fluid">
    <a class="navbar-brand" href="#">Navbar</a>
    <button class="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
      <span class="navbar-toggler-icon"></span>
    </button>
    <div class="collapse navbar-collapse" id="navbarSupportedContent">
      <ul class="navbar-nav me-auto mb-2 mb-lg-0">
        <li class="nav-item">
          <a class="nav-link active" aria-current="page" href="#">Home</a>
        </li>
        <li class="nav-item">
          <a class="nav-link" href="#">Link</a>
        </li>
        <li class="nav-item dropdown">
          <a class="nav-link dropdown-toggle" href="#" role="button" data-bs-toggle="dropdown" aria-expanded="false">
            Dropdown
          </a>
          <ul class="dropdown-menu">
            <li><a class="dropdown-item" href="#">Action</a></li>
            <li><a class="dropdown-item" href="#">Another action</a></li>
            <li><hr class="dropdown-divider" /></li>
            <li><a class="dropdown-item" href="#">Something else here</a></li>
          </ul>
        </li>
        <li class="nav-item">
          <a class="nav-link disabled" aria-disabled="true">Disabled</a>
        </li>
      </ul>
      <form class="d-flex" role="search">
        <input class="form-control me-2" type="search" placeholder="Search" aria-label="Search"/>
        <button class="btn btn-outline-success" type="submit">Search</button>
      </form>
    </div>
  </div>
</nav>
      <nav className="navbar navbar-expand-lg navbar-light iq-navbar" style={{ background: "#004d5c" }} >
        <div className="container-fluid d-flex justify-content-between align-items-center flex-nowrap">

          {/* Logo */}
          <a href="/dashboard" className="navbar-brand d-flex align-items-center mb-0">
            <Image src="../assets/images/logo.jpg" alt="logo" className="me-2" style={{ height: "40px" }} />
            <h4 className="logo-title text-white mb-0">UREDA</h4>
          </a>

          {/* Right Side */}
          <div className="d-flex align-items-center gap-3">
            <div className="text-white small border-right">
              <strong>Welcome, {username}</strong> <br /> Session Expires In:&nbsp;  {String(minutes).padStart(2, "0")}: {String(seconds).padStart(2, "0")}
            </div>
            <Link to="/dashboard" className="btn btn-info btn-sm border-right text-white" title="Go To Dashboard" > 
            <i className="fa fa-dashboard text-white"></i> Dashboard</Link>
            <button className="btn btn-danger btn-sm" onClick={handleLogout} title="Logout" > <i className="fa fa-arrow-right"></i> Logout </button>
          </div>
        </div>
      </nav>
      <div className="iq-navbar-header" style={{ height: "10px" }} ></div>
    </div>
  );
}

export default Header;
